SRC = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "wc_reviews_src.json")
OUT = os.path.join(os.path.dirname(os.path.abspath(__file__)), "part_0.json")

with open(SRC, encoding="utf-8") as f:
    data = json.load(f)

sl = data[0:30]

