result = {}
for item in sl:
    _id = item["id"]
    result[str(_id)] = {"review": translations[_id]}

os.makedirs(os.path.dirname(OUT), exist_ok=True)
with open(OUT, "w", encoding="utf-8") as f:
    json.dump(result, f, ensure_ascii=False, indent=2)

# sanity: confirm literal backslash-n preserved
sample = result[str(sl[0]["id"])]["review"]
assert "\\n\\n" in sample, "literal backslash-n lost"
print("translated", len(result))
print("ids", [it["id"] for it in sl])
